
const DB=window.XHN_DB; const app=document.getElementById('app');
const state={section:'home',detail:null,mode:localStorage.xhnMode||'player',art:localStorage.xhnArt||'reforged',query:''};
const nav=[['home','🏠','Главная'],['heroes','🦸','Герои'],['abilities','✨','Способности'],['items','⚔','Предметы'],['bosses','👹','Боссы'],['systems','⚙','Системы'],['map','🗺','Карта'],['secrets','🔒','Секреты'],['versions','📝','Изменения и загрузки'],['reports','🐞','Баг-репорт']];
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const strip=s=>String(s||'').replace(/\*\*/g,'').replace(/\[\[|\]\]/g,'');
const icon=(type,e,size='')=>{let src=e.web_icons?.[state.art]||e.web_icons?.classic||e.web_icons?.reforged||''; if(src)return `<img class="entity-icon" src="${src}" onerror="this.outerHTML='<div class=placeholder>${esc((e.display_name||e.name_ru||e.name?.ru||'?').slice(0,2))}</div>'">`;return `<div class="placeholder">${esc((e.display_name||e.name_ru||e.name?.ru||e.title||'?').slice(0,2))}</div>`};
const nameOf=(t,e)=>t==='bosses'?(e.name?.ru||e.key):t==='systems'?e.title:(e.display_name||e.name_ru||e.raw_id);
function setSection(s){state.section=s;state.detail=null;const h='#'+s;if(location.hash===h)render();else location.hash=s;scrollTo(0,0)} function openEntity(t,id){state.section=t;state.detail=id;const h='#'+t+'/'+encodeURIComponent(id);if(location.hash===h)render();else location.hash=t+'/'+encodeURIComponent(id);scrollTo(0,0)}
function findEntity(t,id){return DB[t]?.find(e=>(e.raw_id||e.key)===id)}
function modeClass(){return state.mode==='technical'?'mode-technical':state.mode==='research'?'mode-research':'mode-player'}
function shell(body){return `<div class="shell ${modeClass()}"><aside class="sidebar" id="side"><div class="brand"><img src="assets/images/logo-kelthuzad.jpg"><div><h1>X Hero N</h1><p>Энциклопедия карты · 10.7.01</p></div></div><nav class="nav">${nav.map(x=>`<button class="${state.section===x[0]?'active':''}" onclick="setSection('${x[0]}')">${x[1]} ${x[2]}</button>`).join('')}</nav><div class="side-section"><div class="mode-row">${[['player','Игрок'],['technical','Тех.'],['research','Исслед.']].map(x=>`<button class="chip ${state.mode===x[0]?'active':''}" onclick="setMode('${x[0]}')">${x[1]}</button>`).join('')}</div><div class="art-row">${[['classic','Classic'],['reforged','Reforged']].map(x=>`<button class="chip ${state.art===x[0]?'active':''}" onclick="setArt('${x[0]}')">${x[1]}</button>`).join('')}</div></div></aside><main class="content"><div class="topbar"><button class="mobile-menu" onclick="document.getElementById('side').classList.toggle('open')">☰</button><div class="search"><input placeholder="Поиск по всей энциклопедии…" value="${esc(state.query)}" oninput="globalSearch(this.value)"></div></div>${body}<footer class="footer">X Hero N Wiki — неофициальная энциклопедия, созданная сообществом. Версия данных 10.7.01.</footer></main></div>`}
function setMode(m){state.mode=m;localStorage.xhnMode=m;render()} function setArt(a){state.art=a;localStorage.xhnArt=a;render()}
function globalSearch(q){state.query=q;if(q.trim().length>1){state.section='search';state.detail=null}render()}
function home(){const c=DB.meta.counts;return `<section class="hero-banner compact-home-banner"><div class="copy"><div class="eyebrow">База знаний сообщества</div><h2>X Hero N</h2><p>Энциклопедия карты: герои, предметы, боссы, способности, системы, секреты и проверенные игровые механики.</p></div></section><section class="grid section-grid">${[['heroes','🦸','Герои',c.heroes],['abilities','✨','Способности',c.abilities],['items','⚔','Предметы',c.items],['bosses','👹','Боссы',c.bosses],['systems','⚙','Системы',c.systems],['secrets','🔒','Секреты','скрытые механики']].map(x=>`<article class="section-card" onclick="setSection('${x[0]}')"><div class="symbol">${x[1]}</div><div><h3>${x[2]}</h3><b>${x[3]}</b></div></article>`).join('')}</section><section class="grid home-columns"><article class="panel"><h3>С чего начать</h3><div class="steps"><div class="step link" onclick="setSection('systems')">① Основы карты и порталы</div><div class="step link" onclick="setSection('items')">② Первые предметы и сборки</div><div class="step link" onclick="setSection('bosses')">③ Боссы и награды</div><div class="step link" onclick="setSection('secrets')">④ Секретные герои и скрытые механики</div></div></article><article class="panel featured" id="featured"></article></section><section class="grid home-columns"><article class="panel"><h3>Изменения и загрузки</h3><p class="prose">Последняя версия сообщества — <b>10.7.01</b>. Исправлены Гиганский краб и защита Древа в одиночном режиме.</p><button class="primary" onclick="setSection('versions')">Открыть версии</button></article><article class="panel"><h3>Статус базы знаний</h3><div class="stats"><div class="stat"><span>Герои</span><b>${c.heroes}</b></div><div class="stat"><span>Предметы</span><b>${c.items}</b></div><div class="stat"><span>Способности</span><b>${c.abilities}</b></div><div class="stat"><span>Боссы</span><b>${c.bosses}</b></div></div></article></section>`}
let featTimer; function startFeatured(){clearInterval(featTimer);const pool=[['heroes',DB.heroes],['items',DB.items],['bosses',DB.bosses],['systems',DB.systems]];let i=0;const draw=()=>{const el=document.getElementById('featured');if(!el)return;const [t,arr]=pool[i%pool.length],e=arr[(i*7+3)%arr.length];el.innerHTML=`<div class="featured-entry"><div class="eyebrow">Интересная страница · ${label(t)}</div><h4 class="link" onclick="openEntity('${t}','${e.raw_id||e.key}')">${esc(nameOf(t,e))}</h4><p>${esc(summary(t,e))}</p></div>`;i++};draw();featTimer=setInterval(draw,6500)}
function label(t){return {heroes:'Герои',abilities:'Способности',items:'Предметы',bosses:'Боссы',systems:'Системы'}[t]||t}
function summary(t,e){if(t==='heroes')return e.lore?.split('\n').slice(-1)[0]||'Страница героя';if(t==='abilities')return e.display_description||'';if(t==='items')return (e.description||[]).join(' ');if(t==='bosses')return (e.mechanics||[])[0]||e.display_type;if(t==='systems')return e.summary||'';return ''}
function listPage(t,title,subtitle,filterFn=null){let arr=DB[t]||[];if(filterFn)arr=arr.filter(filterFn);const q=(state.query||'').toLowerCase().trim();if(q)arr=arr.filter(e=>JSON.stringify(e).toLowerCase().includes(q));return `<section class="page"><div class="page-title"><div><h2>${title}</h2><p>${subtitle}</p></div></div><div class="toolbar"><input placeholder="Фильтр внутри раздела" oninput="state.query=this.value;render()" value="${esc(state.query)}"><span>${arr.length} записей</span></div><div class="grid cards">${arr.map(e=>card(t,e)).join('')||'<div class="empty">Ничего не найдено.</div>'}</div></section>`}
function card(t,e){return `<article class="card entity-card" onclick="openEntity('${t}','${e.raw_id||e.key}')">${icon(t,e)}<div><h3>${esc(nameOf(t,e))}</h3><p>${esc(summary(t,e).slice(0,155))}</p><div class="technical"><small>${esc(e.raw_id||e.key)}</small></div></div></article>`}
function detailPage(t,e){if(t==='heroes')return heroDetail(e);if(t==='abilities')return abilityDetail(e);if(t==='items')return itemDetail(e);if(t==='bosses')return bossDetail(e);if(t==='systems')return systemDetail(e)}
function panel(title,body,cls=''){return `<section class="panel ${cls}"><h3>${title}</h3>${body}</section>`}
function pageWrap(t,e,body){return `<section class="page"><span class="back" onclick="setSection('${t}')">← ${label(t)}</span>${body}</section>`}
function heroDetail(h){const s=h.stats||{},c=h.combat||{},r=h.base_resources||{};const skills=(h.skills||[]).map(x=>{const a=DB.abilities.find(y=>y.raw_id===x.raw_id);const desc=a?.display_description||'Описание способности пока не извлечено.';const src=a?.web_icons?.[state.art]||'';return `<div class="ability-row" onclick="openEntity('abilities','${x.raw_id}')"><img src="${src}"><div><h4>${esc(x.name)}</h4><p>${esc(desc)}</p></div></div>`}).join('');return pageWrap('heroes',h,`<div class="detail"><div class="main-col">${panel('Герой',`<div class="detail-header">${icon('heroes',h)}<div><h2>${esc(h.name_ru)}</h2><p>${esc(h.proper_name_ru||'')}</p><div class="badges"><span class="badge">${h.primary_attribute==='STR'?'Сила':h.primary_attribute==='AGI'?'Ловкость':'Интеллект'}</span><span class="badge">${c.attack_range>200?'Дальний бой':'Ближний бой'}</span>${h.secret_hero?'<span class="badge">Секретный герой</span>':''}</div></div></div><div class="prose">${esc(h.lore||'').replace(/\n/g,'<br>')}</div>`)}${panel('Характеристики',`<div class="stats"><div class="stat"><span>Сила</span><b>${s.strength??'—'} (+${s.strength_growth??'—'})</b></div><div class="stat"><span>Ловкость</span><b>${s.agility??'—'} (+${s.agility_growth??'—'})</b></div><div class="stat"><span>Интеллект</span><b>${s.intelligence??'—'} (+${s.intelligence_growth??'—'})</b></div><div class="stat"><span>Здоровье</span><b>${r.base_health??'—'}</b></div><div class="stat"><span>Мана</span><b>${r.base_mana??'—'}</b></div><div class="stat"><span>Броня</span><b>${c.defense_base??'—'}</b></div><div class="stat"><span>Атака</span><b>${c.attack_base_min_before_primary_attribute??'—'}–${c.attack_base_max_before_primary_attribute??'—'}</b></div><div class="stat"><span>Дальность атаки</span><b>${c.attack_range??'—'}</b></div><div class="stat"><span>Скорость передвижения</span><b>${c.movement_speed??'—'}</b></div></div>`)}${panel('Способности',`<div class="ability-list">${skills||'<p>Способности не привязаны.</p>'}</div>`)}</div><aside class="aside-col">${panel('Как получить',`<div class="prose">${esc(h.unlock||h.secret_unlock||'Доступен при выборе героя, если не указано иное.')}</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(h.raw_id)}<br><b>Базовый ID:</b> ${esc(h.base_id)}<br><b>Модель:</b> ${esc(h.art?.model||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function abilityDetail(a){const levels=(a.level_data||[]).map(l=>`<div class="difficulty-row"><b>Уровень ${l.level}</b><div class="prose">${esc(l.aub1||'')}</div><small>Мана: ${l.amcs??'—'} · Перезарядка: ${l.acdn??'—'} · Радиус: ${l.aare??'—'} · Дальность: ${l.aran??'—'}</small></div>`).join('');const owners=(a.heroes||[]).map(h=>`<span class="chain-node" onclick="openEntity('heroes','${h.raw_id}')">${esc(h.name)}</span>`).join('');return pageWrap('abilities',a,`<div class="detail"><div class="main-col">${panel('Способность',`<div class="detail-header">${icon('abilities',a)}<div><h2>${esc(a.name_ru)}</h2><p>${esc(a.research_tooltip||'')}</p><div class="badges"><span class="badge">${a.levels||1} ур.</span></div></div></div>`)}${panel('Игровое описание',`<div class="prose">${esc(a.display_description).replace(/\n/g,'<br>')}</div>`)}${panel('Уровни',`<div class="difficulty">${levels||'<p>Отдельные уровни отсутствуют.</p>'}</div>`)}</div><aside class="aside-col">${panel('Владельцы',`<div class="chain">${owners||'Не определены'}</div>`)}${panel('Основные параметры',`<div class="stats"><div class="stat"><span>Уровней</span><b>${a.levels||1}</b></div><div class="stat"><span>Требуемый уровень героя</span><b>${a.required_hero_level??'—'}</b></div><div class="stat"><span>Горячая клавиша</span><b>${esc(a.hotkey_learn||a.hotkey_use||'—')}</b></div></div>`)}${panel('Исследование',`<div class="research-note prose"><span class="status-warn">Статус:</span> данные извлечены из Object Editor; отдельные триггерные эффекты могут требовать проверки.</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(a.raw_id)}<br><b>Base ID:</b> ${esc(a.base_id)}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function itemDetail(it){const bonuses=(it.bonuses||[]).map(b=>`<div class="stat"><span>${esc(b.name)}</span><b>${esc(b.value)}</b></div>`).join('');const obtain=(it.obtain||[]).map(x=>`<div class="stat"><span>${esc(x.field)}</span><b>${esc(x.value)}</b></div>`).join('');const recipe=it.recipe||[];const recipeHtml=recipe.length?`<div class="recipe">${recipe.map((p,i)=>`${i?'<span class="operator">+</span>':''}<div class="recipe-part"><div class="placeholder">${esc((p.name||p.item_name||'?').slice(0,2))}</div><small>${esc(p.name||p.item_name||p.raw_id||'Компонент')}</small></div>`).join('')}<span class="operator">=</span><div class="recipe-part">${icon('items',it)}<small>${esc(it.name_ru)}</small></div></div>`:'<p>Предмет не требует сборки.</p>';const used=(it.used_in_recipes_clean||[]).map(u=>`<span class="chain-node">${esc(u.name)}</span>`).join('');const abs=(it.abilities||[]).map(a=>`<div class="difficulty-row"><b>${esc(a.name)}</b><div>${esc(a.effect||'')}</div></div>`).join('');return pageWrap('items',it,`<div class="detail"><div class="main-col">${panel('Предмет',`<div class="detail-header">${icon('items',it)}<div><h2>${esc(it.name_ru)}</h2><p>${esc(it.name_en||'')}</p><div class="badges"><span class="badge">${esc(it.category||'Предмет')}</span><span class="badge">Уровень ${it.level??'—'}</span></div></div></div><div class="prose">${(it.description||[]).map(x=>strip(x)).map(esc).join('<br>')}</div>`)}${panel('Бонусы',`<div class="stats">${bonuses||'<div>Бонусы не указаны.</div>'}</div>`)}${panel('Получение',`<div class="stats">${obtain||'<div>Источник требует уточнения.</div>'}</div>`)}${panel('Рецепт',recipeHtml)}${panel('Используется в рецептах',`<div class="chain">${used||'Не используется в дальнейших сборках.'}</div>`)}${panel('Способности предмета',`<div class="difficulty">${abs||'Дополнительные способности отсутствуют.'}</div>`)}</div><aside class="aside-col">${panel('Стоимость',`<div class="stats"><div class="stat"><span>Золото</span><b>${it.object_editor?.gold_cost??'—'}</b></div><div class="stat"><span>Древесина</span><b>${it.object_editor?.lumber_cost??'—'}</b></div></div>`)}${panel('Проверенные значения',`<div class="research-note prose">${esc(it.verification_status?.game||'Не проверено')}<br>${esc(it.verification_status?.object_editor||'')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(it.raw_id)}<br><b>Base ID:</b> ${esc(it.base_id)}<br><b>Icon path:</b> ${esc(it.object_editor?.icon||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function bossDetail(b){const type=b.type||'';let location='';if(type==='secret_boss'||type==='secret_miniboss'||type==='dangerous_source'){location=`<div class="stats"><div class="stat"><span>Зона</span><b>${esc(b.area||'—')}</b></div><div class="stat"><span>Как появляется / как открыть</span><b>${esc(b.unlock||'Требует уточнения')}</b></div></div>`}else if(type==='event_boss'){location=`<div class="stats"><div class="stat"><span>Событие</span><b>${esc(b.menu_entry||b.name?.ru)}</b></div><div class="stat"><span>Арена</span><b>${esc(b.portal||b.area||'Событийная арена')}</b></div></div>`}else if(type==='special_boss'){location=`<div class="stats"><div class="stat"><span>Условие доступа</span><b>${esc(b.unlock||'Особое условие')}</b></div><div class="stat"><span>Арена</span><b>${esc(b.area||b.portal||'—')}</b></div></div>`}else{location=`<div class="stats"><div class="stat"><span>Портал / зона</span><b>${esc(b.portal||b.area||'—')}</b></div><div class="stat"><span>Пункт меню</span><b>${esc(b.display_menu_entry||b.name?.ru||'—')}</b></div><div class="stat"><span>Ветка / арена</span><b>${esc(b.chain||'—')}</b></div></div>`}const chain=(b.full_chain||[]).map((n,i)=>`<span class="chain-node ${i===b.chain_index?'current':''}">${esc(n)}</span>${i<(b.full_chain?.length||0)-1?'<span>→</span>':''}`).join('');const rewards=(b.rewards||[]).map(r=>`<div class="difficulty-row"><b>${esc(r.name)}</b>${r.note?`<div>${esc(r.note)}</div>`:''}${r.difficulty?`<small>${esc(r.difficulty)}</small>`:''}</div>`).join('');const mechs=(b.mechanics||[]).map(x=>`<li>${esc(x)}</li>`).join('');const abs=(b.abilities||[]).map(a=>`<div class="ability-row"><div class="placeholder">${esc((a.name||'?').slice(0,2))}</div><div><h4>${esc(a.name||a.raw_id||'Способность')}</h4><p>${esc(a.description||a.effect||'Описание требует извлечения из игровых данных.')}</p></div></div>`).join('');return pageWrap('bosses',b,`<div class="detail"><div class="main-col">${panel('Босс',`<div class="detail-header">${icon('bosses',b)}<div><h2>${esc(b.name?.ru)}</h2><p>${esc(b.name?.en||'')}</p><div class="badges"><span class="badge">${esc(b.display_type)}</span></div></div></div>`)}${panel('Где находится',location)}${b.full_chain?.length?panel('Полная цепочка',`<div class="chain">${chain}</div>`):''}${b.unlock?panel('Как попасть / как открыть',`<div class="prose">${esc(b.unlock)}</div>`):''}${panel('Механика боя',`<ul class="prose">${mechs||'<li>Описание механики требует дополнения.</li>'}</ul>`)}${panel('Способности',`<div class="ability-list">${abs||'<p>Способности ещё не сопоставлены с Object Editor.</p>'}</div>`)}${panel('Награды',`<div class="difficulty">${rewards||'Награда требует уточнения.'}</div>`)}</div><aside class="aside-col">${panel('Статус данных',`<div class="research-note prose">${esc(b.status||'needs_verification')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(b.raw_id||'не сопоставлен')}<br><b>Object Editor:</b> ${esc(b.object_editor_name||'')}<br><b>Модель:</b> ${esc(b.model||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function systemInline(line){
 let x=esc(line);
 x=x.replace(/\[\[boss:([A-Za-z0-9_]+)\|([^\]]+)\]\]/g,(m,key,label)=>`<a class="system-boss-link" href="#bosses/${encodeURIComponent(key)}">${label}</a>`);
 x=x.replace(/\[\[item:([A-Za-z0-9_]+)\|([^\]]+)\]\]/g,(m,raw,label)=>{const it=DB.items.find(x=>x.raw_id===raw);const src=it?.web_icons?.[state.art]||it?.web_icons?.classic||'';return `<a class="system-item-link" href="#items/${encodeURIComponent(raw)}">${src?`<img src="${src}" alt="">`:''}<span>${label}</span></a>`});
 x=x.replace(/\[\[hero:([A-Za-z0-9_]+)\|([^\]]+)\]\]/g,(m,raw,label)=>`<a class="system-boss-link" href="#heroes/${encodeURIComponent(raw)}">${label}</a>`);
 x=x.replace(/\[\[ability:([A-Za-z0-9_]+)\|([^\]]+)\]\]/g,(m,raw,label)=>`<a class="system-boss-link" href="#abilities/${encodeURIComponent(raw)}">${label}</a>`);
 x=x.replace(/\s*@arrow\s*/g,' <span class="system-arrow">→</span> ');
 x=x.replace(/@note\{([^}]+)\}/g,'<span class="system-note">$1</span>');
 return x
}
function systemDetail(s){
 const content=(s.content_clean||s.content||[]).map(line=>{
  if(line.startsWith('## '))return `<h3>${esc(line.slice(3))}</h3>`;
  if(line.startsWith('@chain '))return `<div class="system-chain">${systemInline(line.slice(7))}</div>`;
  if(line.startsWith('@keep '))return `<div class="step system-keep">${systemInline(line.slice(6))}</div>`;
  if(line.startsWith('- '))return `<div class="step">${systemInline(line.slice(2))}</div>`;
  return line?`<p>${systemInline(line)}</p>`:''
 }).join('');
 const guide=s.hide_guide_title?`<section class="panel"><div class="prose">${content}</div></section>`:panel('Гайд',`<div class="prose">${content}</div>`);
 return pageWrap('systems',s,`<div class="detail"><div class="main-col">${panel('Система',`<div class="detail-header">${icon('systems',s)}<div><h2>${esc(s.title)}</h2><p class="prose">${esc(s.summary||'')}</p></div></div>`)}${guide}</div><aside class="aside-col">${panel('Категория',`<p>${esc(s.category||'Система')}</p>`)}${panel('Статус',`<div class="research-note">${esc(s.status||'')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}</aside></div>`)
}
function searchPage(){const q=state.query.toLowerCase().trim();let results=[];for(const t of ['heroes','abilities','items','bosses','systems'])for(const e of DB[t])if(JSON.stringify(e).toLowerCase().includes(q))results.push([t,e]);return `<section class="page"><div class="page-title"><div><h2>Результаты поиска</h2><p>Запрос: ${esc(state.query)}</p></div></div><div class="grid cards">${results.slice(0,120).map(([t,e])=>card(t,e)).join('')||'<div class="empty">Ничего не найдено.</div>'}</div></section>`}
function versions(){return `<section class="page"><div class="page-title"><div><h2>Изменения и загрузки</h2><p>Версии карты и история изменений.</p></div></div><div class="downloads">${DB.versions.map(v=>`<div class="download-row"><div><h3>${esc(v.version)} — ${esc(v.title)}</h3><ul>${v.changes.map(c=>`<li>${esc(c)}</li>`).join('')}</ul></div><a href="${v.file}" download>Скачать карту</a></div>`).join('')}</div></section>`}
function reports(){return `<section class="page"><div class="page-title"><div><h2>Баг-репорт и предложения</h2><p>Форма сохраняет черновик локально. Подключение реальной отправки будет на этапе публикации сайта.</p></div></div>${panel('Сообщить',`<form class="report-form" onsubmit="saveReport(event)"><select id="rt"><option>Ошибка в вики</option><option>Баг карты</option><option>Предложение изменения</option></select><input id="rs" placeholder="Короткий заголовок" required><textarea id="rb" rows="8" placeholder="Опишите проблему или предложение" required></textarea><button class="primary">Сохранить черновик</button></form><div id="reportMsg"></div>`)}</section>`}
function saveReport(e){e.preventDefault();const reports=JSON.parse(localStorage.xhnReports||'[]');reports.push({type:rt.value,subject:rs.value,body:rb.value,date:new Date().toISOString()});localStorage.xhnReports=JSON.stringify(reports);reportMsg.textContent='Черновик сохранён на этом устройстве.';e.target.reset()}
function mapPage(){return `<section class="page"><div class="page-title"><div><h2>Карта</h2><p>Раздел подготовлен под интерактивную карту и игровые скриншоты мест.</p></div></div>${panel('Следующий этап',`<div class="prose">Здесь появятся четыре телепорта, портальные ветки, секретные зоны, Обсерватория, поселение гномов и отмеченные места скрытых мини-боссов.</div>`)}</section>`}
function render(){let body='';if(state.detail){const e=findEntity(state.section,state.detail);body=e?detailPage(state.section,e):'<div class="empty">Страница не найдена.</div>'}else if(state.section==='home')body=home();else if(state.section==='heroes')body=listPage('heroes','Герои','Характеристики, игровые способности и способы открытия.');else if(state.section==='abilities')body=listPage('abilities','Способности','Игровые описания и масштабирование по уровням.');else if(state.section==='items')body=listPage('items','Предметы','Бонусы, источники и визуальные рецепты.');else if(state.section==='bosses')body=listPage('bosses','Боссы','Портальные, событийные, секретные и особые боссы.');else if(state.section==='systems')body=listPage('systems','Системы','Механики и пошаговые гайды.');else if(state.section==='secrets')body=listPage('bosses','Секреты','Секретные боссы и скрытые источники.',e=>['secret_boss','secret_miniboss','dangerous_source','special_boss'].includes(e.type));else if(state.section==='search')body=searchPage();else if(state.section==='versions')body=versions();else if(state.section==='reports')body=reports();else if(state.section==='map')body=mapPage();app.innerHTML=shell(body);if(state.section==='home')startFeatured()}
function initHash(){const h=location.hash.replace(/^#/,'');if(!h)return;const [s,id]=h.split('/');state.section=s||'home';state.detail=id?decodeURIComponent(id):null} window.addEventListener('hashchange',()=>{initHash();render()});
// Alpha 02 presentation overrides
function cleanAbilityText(a){return (a.display_description||a.research_extended||'Игровое описание пока не извлечено.').trim()}
function abilityDetail(a){
 const levels=(a.level_data||[]).map(l=>`<div class="difficulty-row"><b>Уровень ${l.level}</b><div class="prose">${esc(l.aub1||'Описание уровня не извлечено.')}</div><small>${l.amcs?`Мана: ${l.amcs} · `:''}${l.acdn?`Перезарядка: ${l.acdn} сек. · `:''}${l.aare?`Область: ${l.aare} · `:''}${l.aran?`Дальность: ${l.aran}`:''}</small></div>`).join('');
 const owners=(a.heroes||[]).map(h=>`<span class="chain-node" onclick="openEntity('heroes','${h.raw_id}')">${esc(h.name)}</span>`).join('');
 return pageWrap('abilities',a,`<div class="detail"><div class="main-col">${panel('Способность',`<div class="detail-header">${icon('abilities',a)}<div><h2>${esc(a.name_ru)}</h2><p>${esc(a.research_tooltip||'')}</p><div class="badges"><span class="badge">${a.levels||1} ур.</span></div></div></div>`)}${panel('Игровое описание',`<div class="prose preserve-lines">${esc(cleanAbilityText(a))}</div>`)}${panel('Масштабирование по уровням',`<div class="difficulty">${levels||'<p>Способность имеет один уровень или отдельные данные уровней отсутствуют.</p>'}</div>`)}</div><aside class="aside-col">${panel('Владельцы',`<div class="chain">${owners||'Владелец пока не сопоставлен.'}</div>`)}${panel('Основные параметры',`<div class="stats"><div class="stat"><span>Уровней</span><b>${a.levels||1}</b></div><div class="stat"><span>Требуемый уровень героя</span><b>${a.required_hero_level??'—'}</b></div><div class="stat"><span>Горячая клавиша</span><b>${esc(a.hotkey_learn||a.hotkey_use||'—')}</b></div></div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(a.raw_id)}<br><b>Base ID:</b> ${esc(a.base_id)}<br><b>Триггеры:</b> ${esc((a.trigger_references||[]).join(', ')||'нет')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function bossDetail(b){
 const type=b.type||'', nm=b.name?.ru||b.key; let location='';
 if(['secret_boss','secret_miniboss','dangerous_source'].includes(type)) location=`<div class="stats"><div class="stat"><span>Зона</span><b>${esc(b.area||'—')}</b></div><div class="stat wide"><span>Как появляется</span><b>${esc(b.unlock||'Требует уточнения')}</b></div></div>`;
 else if(type==='event_boss') location=`<div class="stats"><div class="stat"><span>Событие</span><b>${esc(b.event_name||nm)}</b></div><div class="stat"><span>Арена</span><b>${esc(b.arena_name||b.area||'Событийная арена')}</b></div></div>`;
 else if(type==='special_boss') location=`<div class="stats"><div class="stat wide"><span>Условие доступа</span><b>${esc(b.unlock||'Особое условие')}</b></div><div class="stat"><span>Арена</span><b>${esc(b.area||b.arena_name||'—')}</b></div></div>`;
 else location=`<div class="stats"><div class="stat"><span>Портал / зона</span><b>${esc(b.portal||b.area||'—')}</b></div><div class="stat"><span>Пункт меню</span><b>${esc(b.correct_menu_entry||nm)}</b></div><div class="stat"><span>Ветка / арена</span><b>${esc(b.arena_name||b.chain||'—')}</b></div></div>`;
 const chain=(b.full_chain||[]).map((n,i)=>`<span class="chain-node ${i===b.chain_index?'current':''}" onclick="openBossByName('${n.replace(/'/g,"\\'")}')">${esc(n)}</span>${i<(b.full_chain?.length||0)-1?'<span>→</span>':''}`).join('');
 const rewards=(b.reward_by_difficulty||[]).length?(b.reward_by_difficulty.map(r=>`<div class="difficulty-row"><b>${esc(r.difficulty)}</b><div>${esc(r.reward)}</div></div>`).join('')):(b.rewards||[]).map(r=>`<div class="difficulty-row"><b>${esc(r.name)}</b>${r.note?`<div>${esc(r.note)}</div>`:''}${r.difficulty?`<small>${esc(r.difficulty)}</small>`:''}</div>`).join('');
 const mechs=(b.mechanics||[]).map(x=>`<li>${esc(x)}</li>`).join('');
 const abs=(b.abilities||[]).map(a=>{const hit=DB.abilities.find(x=>x.raw_id===a.raw_id||x.name_ru===a.name);return `<div class="ability-row" ${hit?`onclick="openEntity('abilities','${hit.raw_id}')"`:''}>${hit?icon('abilities',hit):'<div class="placeholder">'+esc((a.name||'?').slice(0,2))+'</div>'}<div><h4>${esc(a.name||hit?.name_ru||a.raw_id||'Способность')}</h4><p>${esc(a.description||a.effect||hit?.display_description||'Описание требует извлечения из игровых данных.')}</p></div></div>`}).join('');
 return pageWrap('bosses',b,`<div class="detail"><div class="main-col">${panel('Босс',`<div class="detail-header">${icon('bosses',b)}<div><h2>${esc(nm)}</h2><p>${esc(b.name?.en||'')}</p><div class="badges"><span class="badge">${esc(b.display_type)}</span></div></div></div>`)}${panel('Где находится',location)}${b.full_chain?.length?panel('Полная цепочка',`<div class="chain">${chain}</div>`):''}${b.unlock?panel('Как попасть / как открыть',`<div class="prose">${esc(b.unlock)}</div>`):''}${panel('Механика боя',`<ul class="prose">${mechs||'<li>Описание механики требует дополнения.</li>'}</ul>`)}${panel('Способности',`<div class="ability-list">${abs||'<p>Способности ещё не сопоставлены с Object Editor.</p>'}</div>`)}${panel('Награды',`<div class="difficulty">${rewards||'Награда требует уточнения.'}</div>`)}${b.restriction?panel('Ограничение',`<div class="warning-box">${esc(b.restriction)}</div>`):''}</div><aside class="aside-col">${panel('Статус данных',`<div class="research-note prose">${esc(b.status||'needs_verification')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(b.raw_id||'не сопоставлен')}<br><b>Object Editor:</b> ${esc(b.object_editor_name||'')}<br><b>Модель:</b> ${esc(b.model||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function openBossByName(n){const b=DB.bosses.find(x=>(x.name?.ru||'')===n);if(b)openEntity('bosses',b.key)}
function itemDetail(it){
 const bonuses=(it.bonuses||[]).map(b=>`<div class="stat"><span>${esc(b.name)}</span><b>${esc(b.value)}</b></div>`).join('');
 const obtain=(it.obtain||[]).map(x=>`<div class="stat"><span>${esc(x.field)}</span><b>${esc(x.value)}</b></div>`).join('');
 const recipe=it.recipe||[]; const recipeHtml=recipe.length?`<div class="recipe">${recipe.map((p,i)=>{const n=p.name||p.item_name||p.raw_id||'Компонент';const hit=DB.items.find(x=>x.raw_id===p.raw_id||x.name_ru===n);return `${i?'<span class="operator">+</span>':''}<div class="recipe-part" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${hit?icon('items',hit):'<div class="placeholder">'+esc(n.slice(0,2))+'</div>'}<small>${esc(n)}</small></div>`}).join('')}<span class="operator">=</span><div class="recipe-part">${icon('items',it)}<small>${esc(it.name_ru)}</small></div></div>`:'<p>Предмет не требует сборки.</p>';
 const used=(it.used_in_recipes_clean||[]).map(u=>{const hit=DB.items.find(x=>x.name_ru===u.name);return `<span class="chain-node" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${esc(u.name)}</span>`}).join('');
 const abs=(it.abilities||[]).map(a=>`<div class="difficulty-row"><b>${esc(a.name)}</b><div>${esc(a.effect||'')}</div></div>`).join('');
 return pageWrap('items',it,`<div class="detail"><div class="main-col">${panel('Предмет',`<div class="detail-header">${icon('items',it)}<div><h2>${esc(it.name_ru)}</h2><p>${esc(it.name_en||'')}</p><div class="badges"><span class="badge">${esc(it.category||'Предмет')}</span><span class="badge">Уровень ${it.level??'—'}</span></div></div></div><div class="prose">${(it.description||[]).map(x=>strip(x)).map(esc).join('<br>')}</div>`)}${panel('Бонусы',`<div class="stats">${bonuses||'<div>Бонусы не указаны.</div>'}</div>`)}${panel('Получение',`<div class="stats">${obtain||'<div>Источник требует уточнения.</div>'}</div>`)}${panel('Рецепт',recipeHtml)}${panel('Используется в рецептах',`<div class="chain">${used||'Не используется в дальнейших сборках.'}</div>`)}${abs?panel('Способности предмета',`<div class="difficulty">${abs}</div>`):''}</div><aside class="aside-col">${panel('Стоимость',`<div class="stats"><div class="stat"><span>Золото</span><b>${it.object_editor?.gold_cost??'—'}</b></div><div class="stat"><span>Древесина</span><b>${it.object_editor?.lumber_cost??'—'}</b></div></div>`)}${panel('Проверенные значения',`<div class="research-note prose">${esc(it.verification_status?.game||'Не проверено')}<br>${esc(it.verification_status?.object_editor||'')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(it.raw_id)}<br><b>Base ID:</b> ${esc(it.base_id)}<br><b>Icon path:</b> ${esc(it.object_editor?.icon||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)}
function reports(){const repo=DB.meta.github?.repository||'OWNER/XHeroN-Wiki';return `<section class="page"><div class="page-title"><div><h2>Баг-репорт и предложения</h2><p>Заявки будут оформляться через GitHub Issues.</p></div></div>${panel('Создать обращение',`<form class="report-form" onsubmit="openGitHubIssue(event)"><select id="rt"><option>Ошибка в вики</option><option>Баг карты</option><option>Предложение изменения</option></select><input id="rs" placeholder="Короткий заголовок" required><input id="rp" placeholder="Ссылка или название страницы"><textarea id="rb" rows="8" placeholder="Опишите проблему, ожидаемый результат и версию карты" required></textarea><button class="primary">Открыть GitHub Issue</button></form><p class="prose muted">Репозиторий: ${esc(repo)}. Перед публикацией замените OWNER на имя владельца.</p>`)}</section>`}
function openGitHubIssue(e){e.preventDefault();const base=DB.meta.github?.issues_url||'https://github.com/OWNER/XHeroN-Wiki/issues/new';const title=`[${rt.value}] ${rs.value}`;const body=`## Тип\n${rt.value}\n\n## Страница\n${rp.value||location.href}\n\n## Описание\n${rb.value}\n\n## Версия карты\n10.7.01`;window.open(`${base}?title=${encodeURIComponent(title)}&body=${encodeURIComponent(body)}`,'_blank')}
function versions(){const rel=DB.meta.github?.releases_url||'#';return `<section class="page"><div class="page-title"><div><h2>Изменения и загрузки</h2><p>Версии карты, патчноуты и GitHub Releases.</p></div><a class="primary button-link" href="${rel}" target="_blank">Открыть Releases</a></div><div class="downloads">${DB.versions.map(v=>`<div class="download-row"><div><h3>${esc(v.version)} — ${esc(v.title)}</h3><ul>${v.changes.map(c=>`<li>${esc(c)}</li>`).join('')}</ul></div>${v.file&&v.file!=='#'?`<a href="${v.file}" download>Скачать карту</a>`:'<span class="badge">Патчноут</span>'}</div>`).join('')}</div></section>`}

// Alpha 03 overrides
function isVisibleEntity(t,e){return !(t==='items' && e.hidden_player && state.mode==='player')}
function globalSearch(q){
  state.query=q;
  if(q.trim().length>1){state.section='search';state.detail=null}
  const active=document.activeElement;
  const pos=active&&active.selectionStart;
  render();
  requestAnimationFrame(()=>{
    const input=document.querySelector('.topbar .search input');
    if(input){input.focus();const n=Math.min(pos??input.value.length,input.value.length);input.setSelectionRange(n,n)}
  });
}
function listPage(t,title,subtitle,filterFn=null){
 let arr=(DB[t]||[]).filter(e=>isVisibleEntity(t,e));
 if(filterFn)arr=arr.filter(filterFn);
 const q=(state.query||'').toLowerCase().trim();if(q)arr=arr.filter(e=>JSON.stringify(e).toLowerCase().includes(q));
 return `<section class="page"><div class="page-title"><div><h2>${title}</h2><p>${subtitle}</p></div></div><div class="toolbar"><input id="sectionFilter" placeholder="Фильтр внутри раздела" value="${esc(state.query)}"><span>${arr.length} записей</span></div><div class="grid cards">${arr.map(e=>card(t,e)).join('')||'<div class="empty">Ничего не найдено.</div>'}</div></section>`
}
function searchPage(){const q=state.query.toLowerCase().trim();let results=[];for(const t of ['heroes','abilities','items','bosses','systems'])for(const e of DB[t])if(isVisibleEntity(t,e)&&JSON.stringify(e).toLowerCase().includes(q))results.push([t,e]);return `<section class="page"><div class="page-title"><div><h2>Результаты поиска</h2><p>Запрос: ${esc(state.query)}</p></div></div><div class="grid cards">${results.slice(0,120).map(([t,e])=>card(t,e)).join('')||'<div class="empty">Ничего не найдено.</div>'}</div></section>`}
function render(){
 let body='';if(state.detail){const e=findEntity(state.section,state.detail);body=e?detailPage(state.section,e):'<div class="empty">Страница не найдена.</div>'}
 else if(state.section==='home')body=home();else if(state.section==='heroes')body=listPage('heroes','Герои','Характеристики, игровые способности и способы открытия.');else if(state.section==='abilities')body=listPage('abilities','Способности','Игровые описания и масштабирование по уровням.');else if(state.section==='items')body=listPage('items','Предметы','Бонусы, источники и визуальные рецепты.');else if(state.section==='bosses')body=listPage('bosses','Боссы','Портальные, событийные, секретные и особые боссы.');else if(state.section==='systems')body=listPage('systems','Системы','Механики и пошаговые гайды.');else if(state.section==='secrets')body=listPage('bosses','Секреты','Секретные боссы и скрытые источники.',e=>['secret_boss','secret_miniboss','dangerous_source','special_boss'].includes(e.type));else if(state.section==='search')body=searchPage();else if(state.section==='versions')body=versions();else if(state.section==='reports')body=reports();else if(state.section==='map')body=mapPage();
 app.innerHTML=shell(body);
 const sf=document.getElementById('sectionFilter');if(sf){sf.addEventListener('input',e=>{state.query=e.target.value;const p=e.target.selectionStart;render();requestAnimationFrame(()=>{const x=document.getElementById('sectionFilter');if(x){x.focus();x.setSelectionRange(p,p)}})})}
 if(state.section==='home')startFeatured()
}
function rawIdFromItemLink(link){
 const m=String(link||'').match(/(?:^|\/)(I[A-Za-z0-9]{3})_/);return m?m[1]:''
}
function normalizedItemName(name){
 return String(name||'').replace(/\s*[×x]\s*\d+.*/i,'').split('/')[0].trim()
}
function itemByRecipeName(name){
 const n=normalizedItemName(name);return DB.items.find(i=>i.name_ru===n||(i.display_name||'')===n)
}
function itemFromComponent(p){
 const raw=p.raw_id||rawIdFromItemLink(p.component_link||p.link);if(raw){const x=DB.items.find(i=>i.raw_id===raw);if(x)return x}
 return itemByRecipeName(p.component_name||p.name||p.item_name||'')
}
function finalItemForScroll(it){
 if(!/\(Свиток\)/i.test(it.name_ru||''))return null;
 const refs=[...(it.used_in_recipes_clean||[]),...(it.used_in_recipes||[])];
 for(const ref of refs){
  const raw=rawIdFromItemLink(ref.link);let hit=raw?DB.items.find(x=>x.raw_id===raw):null;
  if(!hit)hit=itemByRecipeName(ref.name||'');
  if(hit&&!/\(Свиток\)/i.test(hit.name_ru||'')&&(hit.recipe||[]).length)return hit
 }
 const base=String(it.name_ru||'').replace(/\s*\(Свиток\)\s*$/i,'').trim();
 const hit=DB.items.find(x=>x.name_ru===base);return hit&&(hit.recipe||[]).length?hit:null
}
function recipePartButton(name,hit){
 return `<button type="button" class="recipe-part ${hit?'clickable':''}" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${hit?icon('items',hit):'<div class="placeholder">'+esc(String(name||'?').slice(0,2))+'</div>'}<small>${esc(name)}</small></button>`
}
function renderRecipeNode(p){
 const name=p.component_name||p.name||p.item_name||p.raw_id||'Компонент';
 const explicit=Array.isArray(p.alternatives)?p.alternatives:null;
 const altNames=explicit?explicit.map(x=>x.component_name||x.name||x.item_name||x.raw_id):(/\s+ИЛИ\s+/i.test(name)?name.split(/\s+ИЛИ\s+/i):null);
 if(altNames&&altNames.length>1){
  return `<div class="recipe-alternative-group">${altNames.map((alt,i)=>{const hit=explicit?itemFromComponent(explicit[i]):itemByRecipeName(alt);return `${i?'<span class="choice-operator">ИЛИ</span>':''}${recipePartButton(alt,hit)}`}).join('')}</div>`
 }
 return recipePartButton(name,itemFromComponent(p))
}
function itemDetail(it){
 const bonuses=(it.bonuses||[]).map(b=>`<div class="stat"><span>${esc(b.name)}</span><b>${esc(b.value)}</b></div>`).join('');
 const obtain=(it.obtain||[]).map(x=>`<div class="stat"><span>${esc(x.field)}</span><b>${esc(x.value)}</b></div>`).join('');
 const scrollTarget=finalItemForScroll(it);const resultItem=scrollTarget||it;const recipe=resultItem.recipe||[];
 const recipeHtml=recipe.length?`<div class="recipe">${recipe.map((p,i)=>`${i?'<span class="operator">+</span>':''}${renderRecipeNode(p)}`).join('')}<span class="operator">=</span><button type="button" class="recipe-part clickable" onclick="openEntity('items','${resultItem.raw_id}')">${icon('items',resultItem)}<small>${esc(resultItem.name_ru)}</small></button></div>${scrollTarget?'<p class="recipe-note">Показана полная схема сборки итогового предмета.</p>':''}`:'<p>Предмет не требует сборки.</p>';
 const used=(it.used_in_recipes_clean||[]).map(u=>{const raw=rawIdFromItemLink(u.link);const name=(u.name||'').split('/')[0].trim();const hit=(raw&&DB.items.find(x=>x.raw_id===raw))||DB.items.find(x=>x.name_ru===name);return `<span class="chain-node" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${esc(u.name)}</span>`}).join('');
 const abs=(it.abilities||[]).map(a=>`<div class="difficulty-row"><b>${esc(a.name)}</b><div>${esc(a.effect||'')}</div></div>`).join('');
 return pageWrap('items',it,`<div class="detail"><div class="main-col">${panel('Предмет',`<div class="detail-header">${icon('items',it)}<div><h2>${esc(it.name_ru)}</h2><p>${esc(it.name_en||'')}</p><div class="badges"><span class="badge">${esc(it.category||'Предмет')}</span><span class="badge">Уровень ${it.level??'—'}</span></div></div></div><div class="prose">${(it.description||[]).map(x=>strip(x)).map(esc).join('<br>')}</div>`)}${panel('Бонусы',`<div class="stats">${bonuses||'<div>Бонусы не указаны.</div>'}</div>`)}${panel('Получение',`<div class="stats">${obtain||'<div>Источник требует уточнения.</div>'}</div>`)}${panel('Рецепт',recipeHtml)}${panel('Используется в рецептах',`<div class="chain">${used||'Не используется в дальнейших сборках.'}</div>`)}${abs?panel('Способности предмета',`<div class="difficulty">${abs}</div>`):''}</div><aside class="aside-col">${panel('Стоимость',`<div class="stats"><div class="stat"><span>Золото</span><b>${it.object_editor?.gold_cost??'—'}</b></div><div class="stat"><span>Древесина</span><b>${it.object_editor?.lumber_cost??'—'}</b></div></div>`)}${panel('Проверенные значения',`<div class="research-note prose">${esc(it.verification_status?.game||'Не проверено')}<br>${esc(it.verification_status?.object_editor||'')}</div><div class="player-only">Показывается в режиме исследователя.</div>`)}${panel('Технические данные',`<div class="technical prose"><b>Raw ID:</b> ${esc(it.raw_id)}<br><b>Base ID:</b> ${esc(it.base_id)}<br><b>Icon path:</b> ${esc(it.object_editor?.icon||'')}</div><div class="player-only">Включите технический режим.</div>`)}</aside></div>`)
}
