function tr0610(k){return (UI0610[state.lang]&&UI0610[state.lang][k])||UI0610.ru[k]||k}
function setLang(l){state.lang=l==='en'?'en':'ru';localStorage.xhnLang=state.lang;document.documentElement.lang=state.lang;render()}
function setSection(s){if(s==='secrets')s='systems';state.section=s;state.detail=null;const h='#'+s;if(location.hash===h)render();else location.hash=s;scrollTo(0,0)}
function initHash(){const h=location.hash.replace(/^#/,'');if(!h)return;let [s,id]=h.split('/');if(s==='secrets')s='systems';state.section=s||'home';state.detail=id?decodeURIComponent(id):null}
function entityName0610(t,e){if(state.lang==='en'){if(t==='heroes')return e.name_en||e.name_ru;if(t==='items')return e.name_en||e.name_ru;if(t==='bosses')return e.name?.en||e.name?.ru||e.key;if(t==='systems')return e.title_en||e.title;if(t==='abilities')return e.name_en||e.name_ru||e.raw_id}return t==='bosses'?(e.name?.ru||e.key):t==='systems'?e.title:(e.display_name||e.name_ru||e.raw_id)}
function entitySummary0610(t,e){if(t==='heroes'){const lore=state.lang==='en'?(e.lore_en||e.lore||''):(e.lore||'');let lines=String(lore).split(/\r?\n/).map(x=>x.trim()).filter(Boolean);const divider=lines.findIndex(x=>/^[—–_-]{5,}$/.test(x)||/^The main characteristic\b/i.test(x));if(divider>=0)lines=lines.slice(0,divider);if(lines.length&&/^(Основная характеристика|Primary attribute|The main characteristic)\b/i.test(lines[0]))lines.shift();return lines.join(' ')||tr0610('hero')}if(t==='abilities')return state.lang==='en'?(e.display_description_en||e.display_description||''):(e.display_description||'');if(t==='items'){if(state.lang==='en'&&e.description_en)return e.description_en.join(' ');return (e.description||[]).join(' ')}if(t==='bosses'){if(state.lang==='en'&&e.mechanics_en)return e.mechanics_en[0]||'';return (e.mechanics||[])[0]||e.display_type}if(t==='systems')return state.lang==='en'?(e.summary_en||e.summary):(e.summary||'');return ''}
function label(t){return {heroes:tr0610('heroes'),abilities:tr0610('abilities'),items:tr0610('items'),bosses:tr0610('bosses'),systems:tr0610('systems')}[t]||t}
function attrLabel0610(code){return code==='STR'?tr0610('strength'):code==='AGI'?tr0610('agility'):tr0610('intelligence')}
function heroIconStack0610(h,detail=false){return `<div class="hero-icon-stack ${detail?'detail-stack':''}">${icon('heroes',h)}<img class="primary-attr-icon" src="assets/icons/attributes/${h.primary_attribute||'INT'}.png" title="${esc(attrLabel0610(h.primary_attribute))}" alt="${esc(attrLabel0610(h.primary_attribute))}"></div>`}
function shell(body){const nav0610=[['home','🏠',tr0610('home')],['heroes','🦸',tr0610('heroes')],['abilities','✨',tr0610('abilities')],['items','⚔',tr0610('items')],['bosses','👹',tr0610('bosses')],['systems','⚙',tr0610('systems')],['map','🗺',tr0610('map')],['versions','📝',tr0610('versions')],['reports','🐞',tr0610('reports')]];return `<div class="shell ${modeClass()}"><aside class="sidebar" id="side"><div class="brand"><img src="assets/images/logo-kelthuzad.jpg"><div><h1>X Hero N</h1><p>${tr0610('brand')}</p></div></div><nav class="nav">${nav0610.map(x=>`<button class="${state.section===x[0]?'active':''}" onclick="setSection('${x[0]}')">${x[1]} ${x[2]}</button>`).join('')}</nav><div class="side-section"><div class="mode-row">${[['player',tr0610('player')],['technical',tr0610('technical')],['research',tr0610('research')]].map(x=>`<button class="chip ${state.mode===x[0]?'active':''}" onclick="setMode('${x[0]}')">${x[1]}</button>`).join('')}</div><div class="art-row">${[['classic','Classic'],['reforged','Reforged']].map(x=>`<button class="chip ${state.art===x[0]?'active':''}" onclick="setArt('${x[0]}')">${x[1]}</button>`).join('')}</div><div class="lang-row"><button class="chip ${state.lang==='ru'?'active':''}" onclick="setLang('ru')">RU</button><button class="chip ${state.lang==='en'?'active':''}" onclick="setLang('en')">EN</button></div></div></aside><main class="content"><div class="topbar"><button class="mobile-menu" onclick="document.getElementById('side').classList.toggle('open')">☰</button><div class="search"><input placeholder="${tr0610('search')}" value="${esc(state.query)}" oninput="globalSearch(this.value)"></div></div>${body}<footer class="footer">${tr0610('footer')}</footer></main></div>`}
function home(){const c=DB.meta.counts;const sections=[['heroes','🦸',tr0610('heroes'),c.heroes],['abilities','✨',tr0610('abilities'),c.abilities],['items','⚔',tr0610('items'),c.items],['bosses','👹',tr0610('bosses'),c.bosses],['systems','⚙',tr0610('systems'),c.systems]];return `<section class="hero-banner compact-home-banner"><div class="copy"><div class="eyebrow">${tr0610('community')}</div><h2>X Hero N</h2><p>${tr0610('homeIntro')}</p></div></section><section class="grid section-grid">${sections.map(x=>`<article class="section-card" onclick="setSection('${x[0]}')"><div class="symbol">${x[1]}</div><div><h3>${x[2]}</h3><b>${x[3]}</b></div></article>`).join('')}</section><section class="grid home-columns"><article class="panel"><h3>${tr0610('start')}</h3><div class="steps"><div class="step link" onclick="setSection('systems')">${tr0610('start1')}</div><div class="step link" onclick="setSection('items')">${tr0610('start2')}</div><div class="step link" onclick="setSection('bosses')">${tr0610('start3')}</div><div class="step link" onclick="setSection('systems')">${tr0610('start4')}</div></div></article><article class="panel featured" id="featured"></article></section><section class="grid home-columns"><article class="panel"><h3>${tr0610('changes')}</h3><p class="prose">${tr0610('latest')}</p><button class="primary" onclick="setSection('versions')">${tr0610('openVersions')}</button></article><article class="panel"><h3>${tr0610('status')}</h3><div class="stats"><div class="stat"><span>${tr0610('heroes')}</span><b>${c.heroes}</b></div><div class="stat"><span>${tr0610('items')}</span><b>${c.items}</b></div><div class="stat"><span>${tr0610('abilities')}</span><b>${c.abilities}</b></div><div class="stat"><span>${tr0610('bosses')}</span><b>${c.bosses}</b></div></div></article></section>`}
function startFeatured(){clearInterval(featTimer);const pool=[['heroes',DB.heroes],['items',DB.items],['bosses',DB.bosses],['systems',DB.systems]];let i=0;const draw=()=>{const el=document.getElementById('featured');if(!el)return;const [t,arr]=pool[i%pool.length],e=arr[(i*7+3)%arr.length];el.innerHTML=`<div class="featured-entry"><div class="eyebrow">${tr0610('interesting')} · ${label(t)}</div><h4 class="link" onclick="openEntity('${t}','${e.raw_id||e.key}')">${esc(entityName0610(t,e))}</h4><p>${esc(entitySummary0610(t,e))}</p></div>`;i++};draw();featTimer=setInterval(draw,6500)}
function listPage(t,title,subtitle,filterFn=null){let arr=(DB[t]||[]).filter(e=>isVisibleEntity(t,e));if(filterFn)arr=arr.filter(filterFn);const q=(state.query||'').toLowerCase().trim();if(q)arr=arr.filter(e=>JSON.stringify(e).toLowerCase().includes(q));return `<section class="page"><div class="page-title"><div><h2>${title}</h2><p>${subtitle}</p></div></div><div class="toolbar"><input id="sectionFilter" placeholder="${tr0610('filter')}" value="${esc(state.query)}"><span>${arr.length} ${tr0610('records')}</span></div><div class="grid cards">${arr.map(e=>card(t,e)).join('')||`<div class="empty">${tr0610('nothing')}</div>`}</div></section>`}
function card(t,e){const art=t==='heroes'?heroIconStack0610(e):icon(t,e);return `<article class="card entity-card" onclick="openEntity('${t}','${e.raw_id||e.key}')">${art}<div><h3>${esc(entityName0610(t,e))}</h3><p>${esc(entitySummary0610(t,e).slice(0,155))}</p><div class="technical"><small>${esc(e.raw_id||e.key)}</small></div></div></article>`}
function pageWrap(t,e,body){return `<section class="page"><span class="back" onclick="setSection('${t}')">← ${label(t)}</span>${body}</section>`}
function heroDetail(h){const s=h.stats||{},c=h.combat||{},r=h.base_resources||{};const skills=(h.skills||[]).map(x=>{const a=DB.abilities.find(y=>y.raw_id===x.raw_id);const desc=state.lang==='en'?(a?.display_description_en||a?.display_description||''):(a?.display_description||'');const src=a?.web_icons?.[state.art]||'';return `<div class="ability-row" onclick="openEntity('abilities','${x.raw_id}')"><img src="${src}"><div><h4>${esc(state.lang==='en'?(a?.name_en||x.name):x.name)}</h4><p>${esc(desc)}</p></div></div>`}).join('');const lore=state.lang==='en'?(h.lore_en||h.lore):(h.lore||'');const name=state.lang==='en'?(h.name_en||h.name_ru):h.name_ru;const proper=state.lang==='en'?(h.proper_name_en||h.proper_name_ru||''):(h.proper_name_ru||'');return pageWrap('heroes',h,`<div class="detail"><div class="main-col">${panel(tr0610('hero'),`<div class="detail-header">${heroIconStack0610(h,true)}<div><h2>${esc(name)}</h2><p>${esc(proper)}</p><div class="badges"><span class="badge">${attrLabel0610(h.primary_attribute)}</span><span class="badge">${c.attack_range>200?tr0610('ranged'):tr0610('melee')}</span>${h.secret_hero?`<span class="badge">${tr0610('secretHero')}</span>`:''}</div></div></div><div class="prose">${esc(lore).replace(/\n/g,'<br>')}</div>`)}${panel(tr0610('characteristics'),`<div class="stats"><div class="stat"><span>${tr0610('strength')}</span><b>${s.strength??'—'} (+${s.strength_growth??'—'})</b></div><div class="stat"><span>${tr0610('agility')}</span><b>${s.agility??'—'} (+${s.agility_growth??'—'})</b></div><div class="stat"><span>${tr0610('intelligence')}</span><b>${s.intelligence??'—'} (+${s.intelligence_growth??'—'})</b></div><div class="stat"><span>${tr0610('health')}</span><b>${r.base_health??'—'}</b></div><div class="stat"><span>${tr0610('mana')}</span><b>${r.base_mana??'—'}</b></div><div class="stat"><span>${tr0610('armor')}</span><b>${c.defense_base??'—'}</b></div><div class="stat"><span>${tr0610('attack')}</span><b>${c.attack_base_min_before_primary_attribute??'—'}–${c.attack_base_max_before_primary_attribute??'—'}</b></div><div class="stat"><span>${tr0610('attackRange')}</span><b>${c.attack_range??'—'}</b></div><div class="stat"><span>${tr0610('moveSpeed')}</span><b>${c.movement_speed??'—'}</b></div></div>`)}${panel(tr0610('skills'),`<div class="ability-list">${skills||'<p>—</p>'}</div>`)}</div><aside class="aside-col">${panel(tr0610('howGet'),`<div class="prose">${esc(h.unlock||h.secret_unlock||tr0610('availableDefault'))}</div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(h.raw_id)}<br><b>Base ID:</b> ${esc(h.base_id)}<br><b>Model:</b> ${esc(h.art?.model||'')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)}
function abilityDetail(a){const levels=(a.level_data||[]).map(l=>`<div class="difficulty-row"><b>${tr0610('level')} ${l.level}</b><div class="prose">${esc(l.aub1||'')}</div><small>${l.amcs?`${tr0610('mana')}: ${l.amcs} · `:''}${l.acdn?`${tr0610('cooldown')}: ${l.acdn} · `:''}${l.aare?`${tr0610('area')}: ${l.aare} · `:''}${l.aran?`${tr0610('range')}: ${l.aran}`:''}</small></div>`).join('');const owners=(a.heroes||[]).map(h=>{const hh=DB.heroes.find(x=>x.raw_id===h.raw_id);return `<span class="chain-node" onclick="openEntity('heroes','${h.raw_id}')">${esc(state.lang==='en'?(hh?.name_en||h.name):h.name)}</span>`}).join('');const nm=state.lang==='en'?(a.name_en||a.name_ru):a.name_ru;const desc=state.lang==='en'?(a.display_description_en||cleanAbilityText(a)):cleanAbilityText(a);return pageWrap('abilities',a,`<div class="detail"><div class="main-col">${panel(tr0610('ability'),`<div class="detail-header">${icon('abilities',a)}<div><h2>${esc(nm)}</h2><p>${esc(a.research_tooltip||'')}</p><div class="badges"><span class="badge">${a.levels||1}</span></div></div></div>`)}${panel(tr0610('gameDescription'),`<div class="prose preserve-lines">${esc(desc)}</div>`)}${panel(tr0610('levelScaling'),`<div class="difficulty">${levels||`<p>${tr0610('noLevel')}</p>`}</div>`)}</div><aside class="aside-col">${panel(tr0610('owners'),`<div class="chain">${owners||tr0610('ownerUnknown')}</div>`)}${panel(tr0610('mainParams'),`<div class="stats"><div class="stat"><span>${tr0610('levels')}</span><b>${a.levels||1}</b></div><div class="stat"><span>${tr0610('requiredHeroLevel')}</span><b>${a.required_hero_level??'—'}</b></div><div class="stat"><span>${tr0610('hotkey')}</span><b>${esc(a.hotkey_learn||a.hotkey_use||'—')}</b></div></div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(a.raw_id)}<br><b>Base ID:</b> ${esc(a.base_id)}<br><b>${tr0610('triggers')}:</b> ${esc((a.trigger_references||[]).join(', ')||'—')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)}
const DATAEN0610={'Все характеристики':'All attributes','Сила':'Strength','Ловкость':'Agility','Интеллект':'Intelligence','Разум':'Intelligence','Здоровье':'Health','Мана':'Mana','Защита':'Armor','Броня':'Armor','Атака':'Attack','Скорость атаки':'Attack speed','Скорость передвижения':'Movement speed','Регенерация здоровья':'Health regeneration','Регенерация маны':'Mana regeneration','Активная способность':'Active ability','Пассивная способность':'Passive ability','Тип предмета':'Item type','Результат сборки':'Assembly result','Стоимость':'Cost','Источник':'Source','Тип получения':'Acquisition type','Свиток рецепта':'Recipe scroll','Сборка по рецепту':'Recipe assembly','Предмет':'Item','Рецепт / свиток':'Recipe / scroll','Покупается':'Purchased','Дроп с босса':'Boss drop','Не используется в дальнейших сборках.':'Not used in later combinations.'};
function dataText0610(s){if(state.lang!=='en')return s;return DATAEN0610[String(s)]||s}
function itemLabel0610(it){return state.lang==='en'?(it?.name_en||it?.name_ru||''):(it?.name_ru||'')}
function recipePartButton0610(name,hit){const label=hit?itemLabel0610(hit):name;return `<button type="button" class="recipe-part ${hit?'clickable':''}" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${hit?icon('items',hit):'<div class="placeholder">'+esc(String(name||'?').slice(0,2))+'</div>'}<small>${esc(label)}</small></button>`}
function renderRecipeNode0610(p){const name=p.component_name||p.name||p.item_name||p.raw_id||'Component';const explicit=Array.isArray(p.alternatives)?p.alternatives:null;const altNames=explicit?explicit.map(x=>x.component_name||x.name||x.item_name||x.raw_id):(/\s+ИЛИ\s+/i.test(name)?name.split(/\s+ИЛИ\s+/i):null);if(altNames&&altNames.length>1)return `<div class="recipe-alternative-group">${altNames.map((alt,i)=>{const hit=explicit?itemFromComponent(explicit[i]):itemByRecipeName(alt);return `${i?`<span class="choice-operator">${tr0610('or')}</span>`:''}${recipePartButton0610(alt,hit)}`}).join('')}</div>`;return recipePartButton0610(name,itemFromComponent(p))}
function itemDetail(it){const bonuses=(it.bonuses||[]).map(b=>`<div class="stat"><span>${esc(dataText0610(b.name))}</span><b>${esc(dataText0610(b.value))}</b></div>`).join('');const obtain=(it.obtain||[]).map(x=>`<div class="stat"><span>${esc(dataText0610(x.field))}</span><b>${esc(dataText0610(x.value))}</b></div>`).join('');const scrollTarget=finalItemForScroll(it),resultItem=scrollTarget||it,recipe=resultItem.recipe||[];const recipeHtml=recipe.length?`<div class="recipe">${recipe.map((p,i)=>`${i?'<span class="operator">+</span>':''}${renderRecipeNode0610(p)}`).join('')}<span class="operator">=</span><button type="button" class="recipe-part clickable" onclick="openEntity('items','${resultItem.raw_id}')">${icon('items',resultItem)}<small>${esc(itemLabel0610(resultItem))}</small></button></div>${scrollTarget?`<p class="recipe-note">${tr0610('fullRecipe')}</p>`:''}`:`<p>${tr0610('noRecipe')}</p>`;const used=(it.used_in_recipes_clean||[]).map(u=>{const raw=rawIdFromItemLink(u.link);const nm=(u.name||'').split('/')[0].trim();const hit=(raw&&DB.items.find(x=>x.raw_id===raw))||DB.items.find(x=>x.name_ru===nm);return `<span class="chain-node" ${hit?`onclick="openEntity('items','${hit.raw_id}')"`:''}>${esc(hit?itemLabel0610(hit):u.name)}</span>`}).join('');const abs=(it.abilities||[]).map(a=>`<div class="difficulty-row"><b>${esc(a.name)}</b><div>${esc(a.effect||'')}</div></div>`).join('');const title=itemLabel0610(it),sub=state.lang==='en'?it.name_ru:(it.name_en||'');const desc=(state.lang==='en'&&it.description_en?it.description_en:it.description)||[];return pageWrap('items',it,`<div class="detail"><div class="main-col">${panel(tr0610('item'),`<div class="detail-header">${icon('items',it)}<div><h2>${esc(title)}</h2><p>${esc(sub)}</p><div class="badges"><span class="badge">${esc(dataText0610(it.category||tr0610('item')))}</span><span class="badge">${tr0610('level')} ${it.level??'—'}</span></div></div></div><div class="prose">${desc.map(x=>strip(x)).map(esc).join('<br>')}</div>`)}${panel(tr0610('bonuses'),`<div class="stats">${bonuses||`<div>${tr0610('noBonuses')}</div>`}</div>`)}${panel(tr0610('obtaining'),`<div class="stats">${obtain||`<div>${tr0610('sourceUnknown')}</div>`}</div>`)}${panel(tr0610('recipe'),recipeHtml)}${panel(tr0610('usedIn'),`<div class="chain">${used||tr0610('notUsed')}</div>`)}${abs?panel(tr0610('itemAbilities'),`<div class="difficulty">${abs}</div>`):''}</div><aside class="aside-col">${panel(tr0610('cost'),`<div class="stats"><div class="stat"><span>${tr0610('gold')}</span><b>${it.object_editor?.gold_cost??'—'}</b></div><div class="stat"><span>${tr0610('lumber')}</span><b>${it.object_editor?.lumber_cost??'—'}</b></div></div>`)}${panel(tr0610('verified'),`<div class="research-note prose">${esc(it.verification_status?.game||'')}<br>${esc(it.verification_status?.object_editor||'')}</div><div class="player-only">${tr0610('researchOnly')}</div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(it.raw_id)}<br><b>Base ID:</b> ${esc(it.base_id)}<br><b>Icon path:</b> ${esc(it.object_editor?.icon||'')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)}
function bossDetail(b){const type=b.type||'',nm=state.lang==='en'?(b.name?.en||b.name?.ru||b.key):(b.name?.ru||b.key);let location='';if(['secret_boss','secret_miniboss','dangerous_source'].includes(type))location=`<div class="stats"><div class="stat"><span>${tr0610('zone')}</span><b>${esc(b.area||'—')}</b></div><div class="stat wide"><span>${tr0610('appears')}</span><b>${esc(b.unlock||tr0610('needsClarification'))}</b></div></div>`;else if(type==='event_boss')location=`<div class="stats"><div class="stat"><span>${tr0610('event')}</span><b>${esc(b.event_name||nm)}</b></div><div class="stat"><span>${tr0610('arena')}</span><b>${esc(b.arena_name||b.area||tr0610('eventArena'))}</b></div></div>`;else if(type==='special_boss')location=`<div class="stats"><div class="stat wide"><span>${tr0610('accessCondition')}</span><b>${esc(b.unlock||tr0610('specialCondition'))}</b></div><div class="stat"><span>${tr0610('arena')}</span><b>${esc(b.area||b.arena_name||'—')}</b></div></div>`;else location=`<div class="stats"><div class="stat"><span>${tr0610('portalZone')}</span><b>${esc(b.portal||b.area||'—')}</b></div><div class="stat"><span>${tr0610('menuEntry')}</span><b>${esc(b.correct_menu_entry||nm)}</b></div><div class="stat"><span>${tr0610('branchArena')}</span><b>${esc(b.arena_name||b.chain||'—')}</b></div></div>`;const chain=(b.full_chain||[]).map((n,i)=>`<span class="chain-node ${i===b.chain_index?'current':''}" onclick="openBossByName('${n.replace(/'/g,"\\'")}')">${esc(n)}</span>${i<(b.full_chain?.length||0)-1?'<span>→</span>':''}`).join('');const rewards=(b.reward_by_difficulty||[]).length?b.reward_by_difficulty.map(r=>`<div class="difficulty-row"><b>${esc(r.difficulty)}</b><div>${esc(r.reward)}</div></div>`).join(''):(b.rewards||[]).map(r=>`<div class="difficulty-row"><b>${esc(r.name)}</b>${r.note?`<div>${esc(r.note)}</div>`:''}${r.difficulty?`<small>${esc(r.difficulty)}</small>`:''}</div>`).join('');const mechs=(state.lang==='en'&&b.mechanics_en?b.mechanics_en:b.mechanics||[]).map(x=>`<li>${esc(x)}</li>`).join('');const abs=(b.abilities||[]).map(a=>{const hit=DB.abilities.find(x=>x.raw_id===a.raw_id||x.name_ru===a.name);return `<div class="ability-row" ${hit?`onclick="openEntity('abilities','${hit.raw_id}')"`:''}>${hit?icon('abilities',hit):'<div class="placeholder">'+esc((a.name||'?').slice(0,2))+'</div>'}<div><h4>${esc(state.lang==='en'?(hit?.name_en||a.name||hit?.name_ru||a.raw_id):(a.name||hit?.name_ru||a.raw_id))}</h4><p>${esc(a.description||a.effect||hit?.display_description||'')}</p></div></div>`}).join('');return pageWrap('bosses',b,`<div class="detail"><div class="main-col">${panel(tr0610('boss'),`<div class="detail-header">${icon('bosses',b)}<div><h2>${esc(nm)}</h2><p>${esc(state.lang==='en'?(b.name?.ru||''):(b.name?.en||''))}</p><div class="badges"><span class="badge">${esc(b.display_type)}</span></div></div></div>`)}${panel(tr0610('where'),location)}${b.full_chain?.length?panel(tr0610('fullChain'),`<div class="chain">${chain}</div>`):''}${b.unlock?panel(tr0610('unlock'),`<div class="prose">${esc(b.unlock)}</div>`):''}${panel(tr0610('mechanics'),`<ul class="prose">${mechs||`<li>${tr0610('mechanicsMissing')}</li>`}</ul>`)}${panel(tr0610('skills'),`<div class="ability-list">${abs||`<p>${tr0610('abilitiesMissing')}</p>`}</div>`)}${panel(tr0610('rewards'),`<div class="difficulty">${rewards||tr0610('rewardMissing')}</div>`)}${b.restriction?panel(tr0610('restriction'),`<div class="warning-box">${esc(b.restriction)}</div>`):''}</div><aside class="aside-col">${panel(tr0610('dataStatus'),`<div class="research-note prose">${esc(b.status||'')}</div><div class="player-only">${tr0610('researchOnly')}</div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(b.raw_id||'—')}<br><b>Object Editor:</b> ${esc(b.object_editor_name||'')}<br><b>Model:</b> ${esc(b.model||'')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)}
function systemDetail(s){const lines=state.lang==='en'?(s.content_en||s.content_clean||s.content||[]):(s.content_clean||s.content||[]);const content=lines.map(line=>{if(line.startsWith('## '))return `<h3>${esc(line.slice(3))}</h3>`;if(line.startsWith('@chain '))return `<div class="system-chain">${systemInline(line.slice(7))}</div>`;if(line.startsWith('@keep '))return `<div class="step system-keep">${systemInline(line.slice(6))}</div>`;if(line.startsWith('- '))return `<div class="step">${systemInline(line.slice(2))}</div>`;return line?`<p>${systemInline(line)}</p>`:''}).join('');const guide=s.hide_guide_title?`<section class="panel"><div class="prose">${content}</div></section>`:panel(tr0610('guide'),`<div class="prose">${content}</div>`);const title=state.lang==='en'?(s.title_en||s.title):s.title,summary=state.lang==='en'?(s.summary_en||s.summary):(s.summary||''),category=state.lang==='en'?(s.category_en||s.category):(s.category||tr0610('system'));return pageWrap('systems',s,`<div class="detail"><div class="main-col">${panel(tr0610('system'),`<div class="detail-header">${icon('systems',s)}<div><h2>${esc(title)}</h2><p class="prose">${esc(summary)}</p></div></div>`)}${guide}</div><aside class="aside-col">${panel(tr0610('category'),`<p>${esc(category)}</p>`)}${panel(tr0610('status'),`<div class="research-note">${esc(s.status||'')}</div><div class="player-only">${tr0610('researchOnly')}</div>`)}</aside></div>`)}
function searchPage(){const q=state.query.toLowerCase().trim();let results=[];for(const t of ['heroes','abilities','items','bosses','systems'])for(const e of DB[t])if(isVisibleEntity(t,e)&&JSON.stringify(e).toLowerCase().includes(q))results.push([t,e]);return `<section class="page"><div class="page-title"><div><h2>${tr0610('searchResults')}</h2><p>${tr0610('query')}: ${esc(state.query)}</p></div></div><div class="grid cards">${results.slice(0,120).map(([t,e])=>card(t,e)).join('')||`<div class="empty">${tr0610('nothing')}</div>`}</div></section>`}
function mapPage(){return `<section class="page"><div class="page-title"><div><h2>${tr0610('map')}</h2><p>${tr0610('mapSub')}</p></div></div>${panel(tr0610('nextStage'),`<div class="prose">${tr0610('mapText')}</div>`)}</section>`}
function versions(){const rel=DB.meta.github?.releases_url||'#';return `<section class="page"><div class="page-title"><div><h2>${tr0610('versions')}</h2><p>${tr0610('versionsSub')}</p></div><a class="primary button-link" href="${rel}" target="_blank">${tr0610('releases')}</a></div><div class="downloads">${DB.versions.map(v=>`<div class="download-row"><div><h3>${esc(v.version)} — ${esc(v.title||'')}</h3><ul>${(v.changes||[]).map(c=>`<li>${esc(c)}</li>`).join('')}</ul></div>${v.file&&v.file!=='#'?`<a href="${v.file}" download>${tr0610('download')}</a>`:`<span class="badge">${tr0610('patchNotes')}</span>`}</div>`).join('')}</div></section>`}
function reports(){const repo=DB.meta.github?.repository||'OWNER/XHeroN-Wiki';return `<section class="page"><div class="page-title"><div><h2>${tr0610('reportTitle')}</h2><p>${tr0610('reportSub')}</p></div></div>${panel(tr0610('createRequest'),`<form class="report-form" onsubmit="openGitHubIssue(event)"><select id="rt"><option>${tr0610('wikiError')}</option><option>${tr0610('mapBug')}</option><option>${tr0610('changeRequest')}</option></select><input id="rs" placeholder="${tr0610('shortTitle')}" required><input id="rp" placeholder="${tr0610('pageLink')}"><textarea id="rb" rows="8" placeholder="${tr0610('describe')}" required></textarea><button class="primary">${tr0610('openIssue')}</button></form><p class="prose muted">Repository: ${esc(repo)}</p>`)}</section>`}
function render(){let body='';if(state.section==='secrets')state.section='systems';if(state.detail){const e=findEntity(state.section,state.detail);body=e?detailPage(state.section,e):`<div class="empty">${tr0610('notFound')}</div>`}else if(state.section==='home')body=home();else if(state.section==='heroes')body=listPage('heroes',tr0610('heroes'),tr0610('heroSub'));else if(state.section==='abilities')body=listPage('abilities',tr0610('abilities'),tr0610('abilitySub'));else if(state.section==='items')body=listPage('items',tr0610('items'),tr0610('itemSub'));else if(state.section==='bosses')body=listPage('bosses',tr0610('bosses'),tr0610('bossSub'));else if(state.section==='systems')body=listPage('systems',tr0610('systems'),tr0610('systemSub'));else if(state.section==='search')body=searchPage();else if(state.section==='versions')body=versions();else if(state.section==='reports')body=reports();else if(state.section==='map')body=mapPage();app.innerHTML=shell(body);const sf=document.getElementById('sectionFilter');if(sf)sf.addEventListener('input',e=>{state.query=e.target.value;const p=e.target.selectionStart;render();requestAnimationFrame(()=>{const x=document.getElementById('sectionFilter');if(x){x.focus();x.setSelectionRange(p,p)}})});if(state.section==='home')startFeatured();document.documentElement.lang=state.lang}

