function localized109(ru,en){return state.lang==='en'?(en||ru||''):(ru||en||'')}
function skillSlotLabel109(slot){if(state.lang==='en')return Number(slot)===4?'Ultimate':`Ability ${slot||'—'}`;return Number(slot)===4?'Ульта':`${slot||'—'}-я способность`}
function localizedLevel109(a,l){
 if(state.lang!=='en') return l.aub1||'';
 const desc=a.display_description_en||'';
 const levelNumber=Number(l.level);
 const line=desc.split(/\r?\n/).find(x=>new RegExp(`^Level\\s*${levelNumber}\\s*:`, 'i').test(x.trim()));
 if(line) return line.replace(/^Level\s*\d+\s*:\s*/i,'').trim();
 const en=(a.level_data_en||[]).find(x=>Number(x.level)===levelNumber);
 return en?.aub1_en||l.aub1_en||'See the translated level values above.';
}
function itemBossCard109(b){const name=localized109(b.name_ru,b.name_en),portal=localized109(b.portal,b.portal_en);const chain=state.lang==='en'?(b.full_chain_en||[]):(b.full_chain||[]);const order=chain.length&&Number.isInteger(Number(b.chain_index))?`${Number(b.chain_index)+1} / ${chain.length}`:'—';return `<button type="button" class="item-boss-source" onclick="openEntity('bosses','${esc(b.key)}')"><span class="source-boss-name">${esc(name)}</span><span>${state.lang==='en'?'Teleporter':'Телепорт'}: ${esc(portal||'—')}</span><span>${state.lang==='en'?'Boss order':'Очередь босса'}: ${esc(order)}</span><strong>${state.lang==='en'?'Open boss page →':'Открыть страницу босса →'}</strong></button>`}

heroDetail=function(h){
 const s=h.stats||{},c=h.combat||{},r=h.base_resources||{};
 const sorted=[...(h.skills||[])].sort((x,y)=>(DB.abilities.find(a=>a.raw_id===x.raw_id)?.slot||99)-(DB.abilities.find(a=>a.raw_id===y.raw_id)?.slot||99));
 const skills=sorted.map(x=>{const a=DB.abilities.find(y=>y.raw_id===x.raw_id);const desc=localized109(a?.display_description,a?.display_description_en);const src=a?.web_icons?.[state.art]||a?.web_icons?.classic||'';const slot=a?.slot||x.slot;return `<div class="ability-row ordered-skill" onclick="openEntity('abilities','${x.raw_id}')">${src?`<img src="${src}" alt="">`:'<div class="placeholder">?</div>'}<span class="skill-order-badge">${esc(skillSlotLabel109(slot))}</span><div><h4>${esc(localized109(a?.name_ru||x.name,a?.name_en||x.name_en))}</h4><p>${esc(desc)}</p></div></div>`}).join('');
 const lore=localized109(h.lore,h.lore_en),name=localized109(h.name_ru,h.name_en),proper=localized109(h.proper_name_ru,h.proper_name_en);
 return pageWrap('heroes',h,`<div class="detail"><div class="main-col">${panel(tr0610('hero'),`<div class="detail-header">${heroIconStack0610(h,true)}<div><h2>${esc(name)}</h2><p>${esc(proper)}</p><div class="badges"><span class="badge">${attrLabel0610(h.primary_attribute)}</span><span class="badge">${c.attack_range>200?tr0610('ranged'):tr0610('melee')}</span>${h.secret_hero?`<span class="badge">${tr0610('secretHero')}</span>`:''}</div></div></div><div class="prose">${esc(lore).replace(/\n/g,'<br>')}</div>`)}${panel(tr0610('characteristics'),`<div class="stats"><div class="stat"><span>${tr0610('strength')}</span><b>${s.strength??'—'} (+${s.strength_growth??'—'})</b></div><div class="stat"><span>${tr0610('agility')}</span><b>${s.agility??'—'} (+${s.agility_growth??'—'})</b></div><div class="stat"><span>${tr0610('intelligence')}</span><b>${s.intelligence??'—'} (+${s.intelligence_growth??'—'})</b></div><div class="stat"><span>${tr0610('health')}</span><b>${r.base_health??'—'}</b></div><div class="stat"><span>${tr0610('mana')}</span><b>${r.base_mana??'—'}</b></div><div class="stat"><span>${tr0610('armor')}</span><b>${c.defense_base??'—'}</b></div><div class="stat"><span>${tr0610('attack')}</span><b>${c.attack_base_min_before_primary_attribute??'—'}–${c.attack_base_max_before_primary_attribute??'—'}</b></div><div class="stat"><span>${tr0610('attackRange')}</span><b>${c.attack_range??'—'}</b></div><div class="stat"><span>${tr0610('moveSpeed')}</span><b>${c.movement_speed??'—'}</b></div></div>`)}${panel(tr0610('skills'),`<div class="ability-list">${skills||'<p>—</p>'}</div>`)}</div><aside class="aside-col">${panel(tr0610('howGet'),`<div class="prose">${esc(h.unlock||h.secret_unlock||tr0610('availableDefault'))}</div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(h.raw_id)}<br><b>Model:</b> ${esc(h.art?.model||'')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)
};

