 const rewards=(b.rewards||[]).map(r=>`<div class="difficulty-row reward-row">${rewardButton1081(en?(r.name_en||r.name):r.name,r.type)}${(en?r.note_en:r.note)?`<div class="reward-note">${esc(en?r.note_en:r.note)}</div>`:''}</div>`).join('');
