 return pageWrap('bosses',b,`<div class="detail"><div class="main-col">${panel(en?'Boss':'Босс',`<div class="detail-header">${icon('bosses',b)}<div><h2>${esc(nm)}</h2><p>${esc(en?(b.name?.ru||''):(b.name?.en||''))}</p><div class="badges"><span class="badge">${esc(en?(b.display_type_en||b.display_type):(b.display_type||''))}</span></div></div></div>`)}${panel(en?'Location':'Где находится',location)}${b.full_chain?.length?panel(en?'Full chain':'Полная цепочка',`<div class="chain">${chain}</div>`):''}${localized109(b.unlock,b.unlock_en)?panel(en?'How to access':'Как попасть / как открыть',`<div class="prose">${esc(localized109(b.unlock,b.unlock_en))}</div>`):''}${panel(en?'Fight mechanics':'Механика боя',`<ul class="prose">${mechs||'<li>—</li>'}</ul>`)}${panel(en?'Abilities':'Способности',`<div class="ability-list">${abs||'<p>—</p>'}</div>`)}${panel(en?'Rewards':'Награды',`<div class="difficulty">${rewards||(en?'Reward requires clarification.':'Награда требует уточнения.')}</div>`)}</div><aside class="aside-col">${panel(en?'Data status':'Статус данных',`<div class="research-note prose">${esc(b.status||'needs_verification')}</div><div class="player-only">${tr0610('researchOnly')}</div>`)}${panel(tr0610('technicalData'),`<div class="technical prose"><b>Raw ID:</b> ${esc(b.raw_id||'—')}<br><b>Object Editor:</b> ${esc(b.object_editor_name||'')}<br><b>${en?'Model':'Модель'}:</b> ${esc(b.model||'')}</div><div class="player-only">${tr0610('enableTech')}</div>`)}</aside></div>`)
